refentry.refsect1:
  &reftitle.examples;

   Memcache::setFailureCallback example


<?php

function _failure_callback($host, $tcp_port, $udp_port, $error, $errnum)
{
    echo "Server $host:$tcp_port failed: $error ($errnum)\n";
}

/* OO API */

$memcache = new Memcache;
$memcache->addServer('memcache_host', 11211);
$memcache->setFailureCallback('_failure_callback');

/* procedural API */

$memcache_obj = memcache_connect('memcache_host', 11211);
memcache_set_failure_callback($memcache_obj, '_failure_callback');

?>
